class PIIMasker:
    """Utility to mask PII data for logging purposes."""

    @staticmethod
    def mask_email(email: str) -> str:
        if not email or "@" not in email:
            return "***"
        local, domain = email.split("@", 1)
        if len(local) <= 2:
            masked_local = "*" * len(local)
        else:
            masked_local = local[0] + "*" * (len(local) - 2) + local[-1]
        return f"{masked_local}@{domain}"

    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone:
            return "***"
        digits = "".join(c for c in phone if c.isdigit())
        if len(digits) <= 4:
            return "***"
        return "*" * (len(digits) - 4) + digits[-4:]

    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return "***"
        parts = address.split(",")
        if len(parts) >= 2:
            return f"***, {parts[-1].strip()}"
        return "***"

    @classmethod
    def mask_user_data(cls, user_data: dict) -> dict:
        """Return a masked copy of user data for safe logging."""
        masked = user_data.copy()
        if "email" in masked:
            masked["email"] = cls.mask_email(masked["email"])
        if "phone" in masked:
            masked["phone"] = cls.mask_phone(masked["phone"])
        if "address" in masked:
            masked["address"] = cls.mask_address(masked["address"])
        if "ssn" in masked:
            masked["ssn"] = "***-**-" + masked["ssn"][-4:] if len(masked.get("ssn", "")) >= 4 else "***"
        return masked


class UserDataMessage:
    """Represents a user data message containing PII."""

    def __init__(
        self,
        user_id: str,
        email: str,
        first_name: str,
        last_name: str,
        phone: Optional[str] = None,
        address: Optional[str] = None,
        ssn: Optional[str] = None,
        event_type: str = "user_data_update",
        metadata: Optional[dict] = None,
    ):
        self.message_id = str(uuid.uuid4())
        self.user_id = user_id
        self.email = email
        self.first_name = first_name
        self.last_name = last_name
        self.phone = phone
        self.address = address
        self.ssn = ssn
        self.event_type = event_type
        self.metadata = metadata or {}
        self.timestamp = datetime.utcnow().isoformat() + "Z"

    def to_dict(self) -> dict:
        message = {
            "message_id": self.message_id,
            "event_type": self.event_type,
            "timestamp": self.timestamp,
            "user_data": {
                "user_id": self.user_id,
                "email": self.email,
                "first_name": self.first_name,
                "last_name": self.last_name,
            },
            "metadata": self.metadata,
        }
        if self.phone:
            message["user_data"]["phone"] = self.phone
        if self.address:
            message["user_data"]["address"] = self.address
        if self.ssn:
            message["user_data"]["ssn"] = self.ssn
        return message

    def to_json(self) -> str:
        return json.dumps(self.to_dict())


class SQSUserDataPublisher:
    """
    SQS Publisher for user data messages containing PII.
    
    Supports both standard and FIFO queues. Implements server-side
    encryption (SSE) via SQS queue configuration and ensures PII
    is never logged in plaintext.
    """

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        is_fifo: bool = False,
        message_group_id: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.is_fifo = is_fifo
        self.message_group_id = message_group_id or "user-data-group"
        self.masker = PIIMasker()

        session_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)
        self.sqs_client = session.client("sqs")

        logger.info(f"SQS Publisher initialized for queue: {queue_url}")

    def _build_message_attributes(self, message: UserDataMessage) -> dict:
        """Build SQS message attributes for filtering and routing."""
        attributes = {
            "EventType": {
                "DataType": "String",
                "StringValue": message.event_type,
            },
            "UserId": {
                "DataType": "String",
                "StringValue": message.user_id,
            },
            "MessageId": {
                "DataType": "String",
                "StringValue": message.message_id,
            },
            "Timestamp": {
                "DataType": "String",
                "StringValue": message.timestamp,
            },
            "ContainsPII": {
                "DataType": "String",
                "StringValue": "true",
            },
            "PIIDataTypes": {
                "DataType": "String",
                "StringValue": self._get_pii_data_types(message),
            },
        }
        return attributes

    @staticmethod
    def _get_pii_data_types(message: UserDataMessage) -> str:
        """Identify which PII data types are present in the message."""
        pii_types = ["email", "name"]
        if message.phone:
            pii_types.append("phone")
        if message.address:
            pii_types.append("address")
        if message.ssn:
            pii_types.append("ssn")
        return ",".join(pii_types)

    def publish(self, message: UserDataMessage) -> Optional[dict]:
        """
        Publish a single user data message to SQS.
        
        Returns the SQS response dict on success, None on failure.
        """
        try:
            send_kwargs = {
                "QueueUrl": self.queue_url,
                "MessageBody": message.to_json(),
                "MessageAttributes": self._build_message_attributes(message),
            }

            if self.is_fifo:
                send_kwargs["MessageGroupId"] = self.message_group_id
                send_kwargs["MessageDeduplicationId"] = message.message_id

            response = self.sqs_client.send_message(**send_kwargs)

            masked_data = self.masker.mask_user_data(message.to_dict().get("user_data", {}))
            logger.info(
                f"Message published successfully. "
                f"SQS MessageId: {response.get('MessageId')}, "
                f"Internal MessageId: {message.message_id}, "
                f"Event: {message.event_type}, "
                f"User (masked): {json.dumps(masked_data)}"
            )

            return response

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]
            logger.error(
                f"Failed to publish message {message.message_id}: "
                f"AWS Error [{error_code}]: {error_message}"
            )
            return None
        except Exception as e:
            logger.error(
                f"Unexpected error publishing message {message.message_id}: {str(e)}"
            )
            return None

    def publish_batch(self, messages: list[UserDataMessage]) -> dict:
        """
        Publish a batch of user data messages to SQS (max 10 per batch).
        
        Returns a dict with 'successful' and 'failed' lists.
        """
        results = {"successful": [], "failed": []}

        # SQS allows max 10 messages per batch
        for i in range(0, len(messages), 10):
            batch = messages[i: i + 10]
            entries = []

            for message in batch:
                entry = {
                    "Id": message.message_id,
                    "MessageBody": message.to_json(),
                    "MessageAttributes": self._build_message_attributes(message),
                }
                if self.is_fifo:
                    entry["MessageGroupId"] = self.message_group_id
                    entry["MessageDeduplicationId"] = message.message_id
                entries.append(entry)

            try:
                response = self.sqs_client.send_message_batch(
                    QueueUrl=self.queue_url,
                    Entries=entries,
                )

                successful = response.get("Successful", [])
                failed = response.get("Failed", [])

                for s in successful:
                    logger.info(
                        f"Batch message published. Id: {s['Id']}, "
                        f"SQS MessageId: {s['MessageId']}"
                    )
                results["successful"].extend(successful)

                for f in failed:
                    logger.error(
                        f"Batch message failed. Id: {f['Id']}, "
                        f"Code: {f.get('Code')}, "
                        f"Message: {f.get('Message')}"
                    )
                results["failed"].extend(failed)

            except ClientError as e:
                error_code = e.response["Error"]["Code"]
                error_message = e.response["Error"]["Message"]
                logger.error(
                    f"Batch send failed: AWS Error [{error_code}]: {error_message}"
                )
                for message in batch:
                    results["failed"].append(
                        {"Id": message.message_id, "Code": error_code, "Message": error_message}
                    )
            except Exception as e:
                logger.error(f"Unexpected error in batch send: {str(e)}")
                for message in batch:
                    results["failed"].append(
                        {"Id": message.message_id, "Code": "UnexpectedError", "Message": str(e)}
                    )

        logger.info(
            f"Batch publish complete. "
            f"Successful: {len(results['successful'])}, "
            f"Failed: {len(results['failed'])}"
        )

        return results

    def publish_with_delay(self, message: UserDataMessage, delay_seconds: int = 0) -> Optional[dict]:
        """
        Publish a message with a delivery delay (0-900 seconds).
        """
        if not 0 <= delay_seconds <= 900:
            logger.error(f"Invalid delay_seconds: {delay_seconds}. Must be 0-900.")
            return None

        try:
            send_kwargs = {
                "QueueUrl": self.queue_url,
                "MessageBody": message.to_json(),
                "MessageAttributes": self._build_message_attributes(message),
                "DelaySeconds": delay_seconds,
            }

            if self.is_fifo:
                send_kwargs["MessageGroupId"] = self.message_group_id
                send_kwargs["MessageDeduplicationId"] = message.message_id

            response = self.sqs_client.send_message(**send_kwargs)

            logger.info(
                f"Delayed message published (delay={delay_seconds}s). "
                f"SQS MessageId: {response.get('MessageId')}, "
                f"Internal MessageId: {message.message_id}"
            )

            return response

        except ClientError as e:
            logger.error(
                f"Failed to publish delayed message {message.message_id}: "
                f"{e.response['Error']['Message']}"
            )
            return None

    def create_encrypted_queue(
        self,
        queue_name: str,
        kms_master_key_id: str = "alias/aws/sqs",
        is_fifo: bool = False,
    ) -> Optional[str]:
        """
        Create a new SQS queue with server-side encryption enabled.
        Returns the queue URL or None on failure.
        """
        try:
            attributes = {
                "KmsMasterKeyId": kms_master_key_id,
                "KmsDataKeyReusePeriodSeconds": "300",
                "MessageRetentionPeriod": "345600",  # 4 days
                "VisibilityTimeout": "60",
            }

            if is_fifo:
                attributes["FifoQueue"] = "true"
                attributes["ContentBasedDeduplication"] = "false"
                if not queue_name.endswith(".fifo"):
                    queue_name += ".fifo"

            response = self.sqs_client.create_queue(
                QueueName=queue_name,
                Attributes=attributes,
                tags={
                    "DataClassification": "PII",
                    "Service": "user-data-publisher",
                },
            )

            queue_url = response["QueueUrl"]
            logger.info(f"Created encrypted queue: {queue_url}")
            return queue_url

        except ClientError as e:
            logger.error(f"Failed to create queue: {e.response['Error']['Message']}")
            return None


